-- FerrumIT Market Rate Analysis Migration
-- Run in Supabase SQL Editor

-- 1. Market rate analyses table
CREATE TABLE IF NOT EXISTS market_rate_analyses (
  id                 uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  zip                text,
  city               text NOT NULL,
  state              text NOT NULL,
  col_index          numeric,
  median_income      numeric,
  unemployment_rate  numeric,
  market_tier        text NOT NULL DEFAULT 'standard',
  pricing_multiplier numeric NOT NULL DEFAULT 1.0,
  rates              jsonb NOT NULL DEFAULT '{}',
  afterhours_rates   jsonb,
  market_notes       text,
  analysis_source    text NOT NULL DEFAULT 'ai_generated',
  analyzed_at        timestamptz NOT NULL DEFAULT now(),
  created_at         timestamptz NOT NULL DEFAULT now(),
  updated_at         timestamptz NOT NULL DEFAULT now(),
  UNIQUE(city, state)
);

-- 2. Quote rate sheets table
CREATE TABLE IF NOT EXISTS quote_rate_sheets (
  id             uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  quote_id       uuid REFERENCES quotes(id) ON DELETE CASCADE,
  analysis_id    uuid REFERENCES market_rate_analyses(id),
  market_zip     text,
  market_city    text,
  market_state   text,
  accepted_rates jsonb NOT NULL,
  overrides      jsonb NOT NULL DEFAULT '{}',
  accepted_by    uuid REFERENCES profiles(id),
  accepted_at    timestamptz NOT NULL DEFAULT now(),
  created_at     timestamptz NOT NULL DEFAULT now(),
  UNIQUE(quote_id)
);

-- 3. RLS policies
ALTER TABLE market_rate_analyses ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Authenticated read market analyses" ON market_rate_analyses;
DROP POLICY IF EXISTS "Authenticated write market analyses" ON market_rate_analyses;
CREATE POLICY "Authenticated read market analyses"   ON market_rate_analyses FOR SELECT TO authenticated USING (true);
CREATE POLICY "Authenticated write market analyses"  ON market_rate_analyses FOR ALL    TO authenticated USING (true) WITH CHECK (true);

ALTER TABLE quote_rate_sheets ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Authenticated manage rate sheets" ON quote_rate_sheets;
CREATE POLICY "Authenticated manage rate sheets" ON quote_rate_sheets FOR ALL TO authenticated USING (true) WITH CHECK (true);

